precision mediump float;
uniform sampler2D u_texture;
uniform float u_time;
uniform vec2 u_resolution;
varying vec2 v_uv;

void main()
{
    vec3 originalColor = texture2D(u_texture, v_uv).rgb;
    float luminance = dot(originalColor, vec3(0.2126, 0.7152, 0.0722));

    vec3 color;
    if (luminance < 0.25)      color = mix(vec3(0.0, 0.0, 0.0), vec3(0.0, 0.0, 0.6), luminance / 0.25);
    else if (luminance < 0.5)  color = mix(vec3(0.0, 0.0, 0.6), vec3(0.5, 0.0, 0.6), (luminance - 0.25) / 0.25);
    else if (luminance < 0.75) color = mix(vec3(0.5, 0.0, 0.6), vec3(0.95, 0.1, 0.05), (luminance - 0.5) / 0.25);
    else               color = mix(vec3(0.95, 0.1, 0.05), vec3(1.0, 1.0, 0.2), (luminance - 0.75) / 0.25);

    float neonIntensity = 1.5;
    vec3 neonGlow = originalColor * neonIntensity;

    vec3 finalColor = color + neonGlow;

    gl_FragColor = vec4(clamp(finalColor, 0.0, 1.0), 1.0);
}

