response:
precision mediump float;
uniform sampler2D u_texture;
uniform float u_time;
uniform vec2 u_resolution;
varying vec2 v_uv;

void main()
{
    vec2 neon_color = vec2(0.0, 0.0, 1.0);
    float intensity = 0.1;
    float glow_strength = 1.5;

    vec2 cell = vec2(16.0) / u_resolution;
    vec2 snapped = (floor(v_uv / cell) + 0.5) * cell;

    vec3 color = texture2D(u_texture, snapped).rgb;

    float brightness = dot(color, vec3(0.2126, 0.7152, 0.0722));

    vec3 final_color = color * (brightness * intensity);

    gl_FragColor = vec4(clamp(final_color, 0.0, 1.0), 1.0);
}
}

